from flask_login import current_user, login_required
from app.services.auth_service import register_user, authenticate_user, logout_current_user, change_password

auth_bp = Blueprint('auth', __name__, url_prefix='/api/auth')


@auth_bp.route('/register', methods=['POST'])
def register():
    data = request.get_json(silent=True) or {}
    required = ['username', 'password']
    for field in required:
        if not data.get(field):
            return jsonify({'error': f'{field} is required'}), 400
    try:
        user = register_user(
            username=data['username'],
            password=data['password'],
            email=data.get('email'),
            full_name=data.get('full_name'),
        )
    except ValueError as e:
        return jsonify({'error': str(e)}), 409
    return jsonify(user.to_dict()), 201


@auth_bp.route('/login', methods=['POST'])
def login():
    data = request.get_json(silent=True) or {}
    user = authenticate_user(
        username=data.get('username', ''),
        password=data.get('password', ''),
        ip_address=request.remote_addr,
    )
    if not user:
        return jsonify({'error': 'Invalid credentials'}), 401
    return jsonify(user.to_dict()), 200


@auth_bp.route('/logout', methods=['POST'])
@login_required
def logout():
    logout_current_user(user_id=current_user.id)
    return jsonify({'message': 'Logged out'}), 200


@auth_bp.route('/me', methods=['GET'])
@login_required
def me():
    return jsonify(current_user.to_dict()), 200


@auth_bp.route('/change-password', methods=['POST'])
@login_required
def change_pw():
    data = request.get_json(silent=True) or {}
    try:
        change_password(current_user, data.get('old_password', ''), data.get('new_password', ''))
    except ValueError as e:
        return jsonify({'error': str(e)}), 400
    return jsonify({'message': 'Password updated'}), 200
"}

