def list_drugs():
    q = request.args.get('q')
    if q:
        drugs = search_drugs(q, limit=request.args.get('limit', 50, type=int))
    else:
        status = request.args.get('status')
        query = Drug.query
        if status:
            query = query.filter_by(status=status)
        drugs = query.order_by(Drug.generic_name).limit(
