class TestRegister:
    def test_register_success(self, client):
        resp = client.post('/api/auth/register', json={
            'username': 'newuser',
            'password': 'pass1234',
            'email': 'newuser@test.com',
        })
        assert resp.status_code == 201
        data = resp.get_json()
        assert data['username'] == 'newuser'

    def test_register_duplicate_username(self, client):
        client.post('/api/auth/register', json={'username': 'dup', 'password': 'pass'})
        resp = client.post('/api/auth/register', json={'username': 'dup', 'password': 'pass2'})
        assert resp.status_code == 409

    def test_register_missing_username(self, client):
        resp = client.post('/api/auth/register', json={'password': 'pass'})
        assert resp.status_code == 400


class TestLogin:
    def test_login_success(self, client):
        client.post('/api/auth/register', json={'username': 'logintest', 'password': 'correct'})
        resp = client.post('/api/auth/login', json={'username': 'logintest', 'password': 'correct'})
        assert resp.status_code == 200

    def test_login_wrong_password(self, client):
        client.post('/api/auth/register', json={'username': 'wrongpw', 'password': 'correct'})
        resp = client.post('/api/auth/login', json={'username': 'wrongpw', 'password': 'wrong'})
        assert resp.status_code == 401

    def test_login_unknown_user(self, client):
        resp = client.post('/api/auth/login', json={'username': 'nobody', 'password': 'pass'})
        assert resp.status_code == 401


class TestMe:
    def test_me_unauthenticated(self, client):
        resp = client.get('/api/auth/me')
        assert resp.status_code == 401

    def test_me_authenticated(self, client):
        client.post('/api/auth/login', json={'username': 'admin', 'password': 'admin123'})
        resp = client.get('/api/auth/me')
        assert resp.status_code == 200
        assert resp.get_json()['username'] == 'admin'


class TestLogout:
    def test_logout(self, client):
        client.post('/api/auth/login', json={'username': 'admin', 'password': 'admin123'})
        resp = client.post('/api/auth/logout')
        assert resp.status_code == 200
        resp2 = client.get('/api/auth/me')
        assert resp2.status_code == 401
"}

