Fix Permission Service with Org Hierarchy and Build Admin Pages

```
Read the existing codebase before making changes. Focus on the permission system and admin UI.

TASK 1: Fix app/services/permission_service.py — add org hierarchy support

The current has_permission() only checks role permissions and temp grants. It does NOT check org unit scope. Modify it to accept an optional org_unit_id parameter:

    def has_permission(user: User, codename: str, org_unit_id: int | None = None) -> bool:

Add org unit checking logic:
(a) First do the existing role and temp grant checks (keep them).
(b) If org_unit_id is provided AND the user has the permission (from step a), ALSO verify the user has access to that org unit. A user has access if:
    - They belong to that exact org unit (via UserOrgUnit), OR
    - They belong to any ANCESTOR of that org unit (campus user can access department resources)

    To check ancestors, walk up the OrgUnit.parent_id chain:
        from app.models.organization import OrgUnit, UserOrgUnit
        user_org_ids = {uo.org_unit_id for uo in UserOrgUnit.query.filter_by(user_id=user.id).all()}
        if org_unit_id in user_org_ids:
            return True
        # Walk up the tree
        current = OrgUnit.query.get(org_unit_id)
        while current and current.parent_id:
            if current.parent_id in user_org_ids:
                return True
            current = OrgUnit.query.get(current.parent_id)
        return False

(c) If org_unit_id is NOT provided, skip the org check (return True if permission exists).

Also add a function to prevent removing the last org_admin:

    def remove_role(user: User, role: Role, admin_id: int) -> None:
        if role.name == 'org_admin':
            admin_count = db.session.query(User).join(User.roles).filter(Role.name == 'org_admin', User.is_active == True).count()
            if admin_count <= 1:
                raise ValueError("Cannot remove the last org_admin role")
        # ... rest of existing logic

Add a function for the permission audit report:

    def get_permission_audit_report(org_unit_id=None, start_date=None, end_date=None):
        """Return permission-related audit log entries."""
        from app.models.audit import AuditLog
        query = AuditLog.query.filter(AuditLog.action.like('permission.%'))
        if start_date:
            query = query.filter(AuditLog.timestamp >= start_date)
        if end_date:
            query = query.filter(AuditLog.timestamp <= end_date)
        entries = query.order_by(AuditLog.timestamp.desc()).all()
        return [e.to_dict() for e in entries]

    def export_permission_audit_csv(entries: list[dict]) -> str:
        """Convert audit entries to CSV string."""
        import csv, io
        output = io.StringIO()
        writer = csv.writer(output)
        writer.writerow(['Timestamp', 'User ID', 'Action', 'Resource Type', 'Resource ID', 'Details'])
        for e in entries:
            writer.writerow([e.get('timestamp'), e.get('user_id'), e.get('action'),
                             e.get('resource_type'), e.get('resource_id'),
                             str(e.get('new_value', e.get('old_value', '')))])
        return output.getvalue()

TASK 2: Update the require_permission decorator in app/utils/decorators.py

Modify require_permission to optionally extract org_unit_id from the request:

    def require_permission(codename: str, org_unit_param: str | None = None):
        def decorator(f):
            @functools.wraps(f)
            def wrapped(*args, **kwargs):
                if not current_user.is_authenticated:
                    return jsonify({'error': 'Authentication required'}), 401
                from app.services.permission_service import has_permission
                org_unit_id = None
                if org_unit_param:
                    org_unit_id = kwargs.get(org_unit_param) or request.args.get(org_unit_param, type=int)
                if not has_permission(current_user, codename, org_unit_id=org_unit_id):
                    return jsonify({'error': 'Permission denied'}), 403
                return f(*args, **kwargs)
            return wrapped
        return decorator

TASK 3: Build admin page routes

Create a new file app/api/page_routes.py for all HTML page routes that don't belong to a specific feature:

    from flask import Blueprint, render_template, redirect, request, flash, Response
    from flask_login import login_required, current_user
    from app.utils.decorators import require_role
    from app.models.user import User, Role
    from app.models.organization import OrgUnit
    from app.services.permission_service import get_permission_audit_report, export_permission_audit_csv

    pages_bp = Blueprint('pages', __name__)

    @pages_bp.route('/dashboard')
    @login_required
    def dashboard():
        return render_template('dashboard.html')

    @pages_bp.route('/admin')
    @login_required
    @require_role('org_admin')
    def admin_panel():
        return render_template('admin/index.html')

    @pages_bp.route('/admin/users')
    @login_required
    @require_role('org_admin')
    def admin_users():
        search = request.args.get('search', '').strip()
        query = User.query
        if search:
            query = query.filter(User.username.ilike(f'%{search}%') | User.full_name.ilike(f'%{search}%'))
        users = query.order_by(User.created_at.desc()).all()
        roles = Role.query.all()
        if request.headers.get('HX-Request'):
            return render_template('admin/partials/user_table.html', users=users, roles=roles)
        return render_template('admin/users.html', users=users, roles=roles)

    @pages_bp.route('/admin/permissions/audit')
    @login_required
    @require_role('org_admin')
    def permission_audit():
        start = request.args.get('start_date')
        end = request.args.get('end_date')
        entries = get_permission_audit_report(start_date=start, end_date=end)
        fmt = request.args.get('format')
        if fmt == 'csv':
            csv_data = export_permission_audit_csv(entries)
            return Response(csv_data, mimetype='text/csv',
                            headers={'Content-Disposition': 'attachment; filename=permission_audit.csv'})
        if request.headers.get('HX-Request'):
            return render_template('admin/partials/audit_table.html', entries=entries)
        return render_template('admin/permission_audit.html', entries=entries)

Register pages_bp in app/api/__init__.py with NO url_prefix (so routes are at /dashboard, /admin, etc.).

