    <h3>Status</h3>
    <span class="badge badge-{{ listing.status }} badge-lg">{{ listing.status | replace('_', ' ') | title }}</span>

    {% if listing.published_at %}
    <p class="status-meta">Published: {{ listing.published_at.strftime('%Y-%m-%d %H:%M') }} UTC</p>
    {% endif %}
    {% if listing.locked_at %}
    <p class="status-meta">Locked: {{ listing.locked_at.strftime('%Y-%m-%d %H:%M') }} UTC</p>
    {% endif %}

    <div class="status-actions">
        {% set allowed = {
            'draft': ['pending_review'],
            'pending_review': ['published', 'draft'],
            'published': ['unpublished', 'expired', 'locked'],
            'unpublished': ['draft', 'locked'],
            'expired': ['locked'],
            'locked': ['draft'],
        } %}
        {% set next_statuses = allowed.get(listing.status, []) %}
        {% if next_statuses %}
        <form method="POST" action="/listings/{{ listing.id }}/status"
