                    <label class="checkbox-label">
                        <input type="checkbox" name="attended_users" value="{{ a.user_id }}" {% if a.attended %}checked{% endif %}>
                        {{ a.user.full_name or a.user.username if a.user else 'User #' ~ a.user_id }}
                    </label>
                {% endfor %}
                <button class="btn btn-primary" style="margin-top:0.5rem;">Save Attendance</button>
            </form>
        </div>
        {% endif %}

        <div class="card" style="margin-top:1rem;">
            <h2>Reviews</h2>
            {% if total > 0 %}
                <div class="review-stats">
                    <span class="stat-big">{{ average_rating }}</span>
                    <span class="star-rating">{% for i in range(1, 6) %}{% if i <= average_rating|int %}★{% else %}☆{% endif %}{% endfor %}</span>
                    <span class="text-muted">({{ total }} review{{ 's' if total != 1 }})</span>
                </div>
            {% endif %}
            {% for r in reviews %}
                <div class="review-card card" style="margin-top:0.5rem;">
                    <div class="review-header">
                        <strong>{{ r.reviewer_display }}</strong>
                        <span class="star-rating">{% for i in range(1, 6) %}{% if i <= r.rating %}★{% else %}☆{% endif %}{% endfor %}</span>
                        <span class="text-muted">{{ r.created_at }}</span>
                    </div>
                    {% if r.tags %}
                        <div class="pills">{% for t in r.tags %}<span class="pill">{{ t | replace('_', ' ') | title }}</span>{% endfor %}</div>
