                    {% if r.comment %}<p>{{ r.comment }}</p>{% endif %}
                    {% if r.coach_reply %}
                        <div class="coach-reply" style="margin-left:2rem;border-left:3px solid var(--primary);padding-left:1rem;margin-top:0.5rem;">
