                            <p>{{ r.coach_reply.body }}</p>
                        </div>
                    {% elif is_instructor %}
                        <form method="POST" action="/classes/{{ tc.id }}/reviews/{{ r.id }}/reply" style="margin-left:2rem;margin-top:0.5rem;">
                            <input type="hidden" name="csrf_token" value="{{ csrf_token() }}">
                            <textarea name="body" class="form-input" rows="2" placeholder="Write a reply..." minlength="10" maxlength="2000" required></textarea>
                            <button class="btn btn-sm btn-secondary" style="margin-top:0.25rem;">Post Reply</button>
                        </form>
                    {% endif %}
                </div>
            {% endfor %}
            {% if can_review %}
