TASK 1: Implement the service worker at app/static/js/sw.js

Replace the current file content with a complete service worker:

    const CACHE_NAME = 'clinical-ops-v1';
    const STATIC_ASSETS = [
        '/',
        '/static/css/main.css',
        '/static/js/app.js',
    ];

    self.addEventListener('install', event => {
        event.waitUntil(
            caches.open(CACHE_NAME).then(cache => cache.addAll(STATIC_ASSETS))
        );
        self.skipWaiting();
    });

    self.addEventListener('activate', event => {
        event.waitUntil(
            caches.keys().then(keys =>
                Promise.all(keys.filter(k => k !== CACHE_NAME).map(k => caches.delete(k)))
            )
        );
        self.clients.claim();
    });

    self.addEventListener('fetch', event => {
        const { method, url } = event.request;
        if (method !== 'GET') {
            // For write requests, try network first; if offline, return a queued response
            event.respondWith(
                fetch(event.request.clone()).catch(() => {
                    return new Response(
                        JSON.stringify({ queued: true, message: 'Your change has been queued and will sync when online.' }),
                        { status: 202, headers: { 'Content-Type': 'application/json' } }
                    );
                })
            );
            return;
        }
        // GET requests: stale-while-revalidate
        event.respondWith(
            caches.match(event.request).then(cached => {
                const fetchPromise = fetch(event.request).then(response => {
                    if (response.ok) {
                        const clone = response.clone();
                        caches.open(CACHE_NAME).then(cache => cache.put(event.request, clone));
                    }
                    return response;
                }).catch(() => cached);
                return cached || fetchPromise;
            })
        );
    });

