TASK 3: Fix the server-side job queue processor

In app/services/queue_service.py, add a job processing function (the current file likely only has enqueue/claim/complete/fail):

    import time, math, random, threading
    from datetime import datetime, timezone, timedelta

    def process_pending_jobs():
        """Process all pending jobs that are ready to run."""
        from app.models.queue import JobQueue
        from app.extensions import db
        from app.utils.constants import JobStatus
        now = datetime.now(timezone.utc)
        jobs = JobQueue.query.filter(
            JobQueue.status == JobStatus.PENDING.value,
            (JobQueue.next_retry_at == None) | (JobQueue.next_retry_at <= now)
        ).order_by(JobQueue.created_at).limit(10).all()
        for job in jobs:
            job.status = JobStatus.PROCESSING.value
            job.started_at = now
            db.session.commit()
            try:
                _dispatch_job(job)
                job.status = JobStatus.COMPLETED.value
                job.completed_at = datetime.now(timezone.utc)
            except Exception as e:
                job.attempts += 1
                if job.attempts >= job.max_attempts:
                    job.status = JobStatus.DEAD_LETTER.value
                else:
                    job.status = JobStatus.PENDING.value
                    backoff = min(5 * (2 ** job.attempts), 300) * (0.9 + random.random() * 0.2)
                    job.next_retry_at = datetime.now(timezone.utc) + timedelta(seconds=backoff)
                job.error_message = str(e)
            db.session.commit()

    JOB_HANDLERS = {}

    def register_job_handler(job_type: str, handler):
        JOB_HANDLERS[job_type] = handler

    def _dispatch_job(job):
        handler = JOB_HANDLERS.get(job.job_type)
        if not handler:
            raise ValueError(f"No handler registered for job type: {job.job_type}")
        import json
        payload = json.loads(job.payload) if job.payload else {}
        handler(payload)

