- create_backup(db_path, backup_dir) copies the SQLite file using sqlite3 backup API (not just file copy)
- prune_old_backups(backup_dir) deletes files older than 30 days
- list_backups(backup_dir) returns a list of dicts with filename, size, created date

If the existing implementation already does this correctly, leave it. If it's a stub, implement it:

    import sqlite3, os, shutil
    from datetime import datetime

    def create_backup(db_path: str, backup_dir: str) -> str:
        os.makedirs(backup_dir, exist_ok=True)
        timestamp = datetime.utcnow().strftime('%Y%m%d_%H%M%S')
        backup_path = os.path.join(backup_dir, f'backup_{timestamp}.db')
        src = sqlite3.connect(db_path)
        dst = sqlite3.connect(backup_path)
        src.backup(dst)
        dst.close()
        src.close()
        return backup_path

    def prune_old_backups(backup_dir: str, retention_days: int = 30) -> int:
        import time
        cutoff = time.time() - (retention_days * 86400)
        count = 0
        if not os.path.exists(backup_dir):
            return 0
        for f in os.listdir(backup_dir):
            fp = os.path.join(backup_dir, f)
            if os.path.isfile(fp) and os.path.getmtime(fp) < cutoff:
                os.remove(fp)
                count += 1
        return count

    def list_backups(backup_dir: str) -> list:
        if not os.path.exists(backup_dir):
            return []
        backups = []
        for f in sorted(os.listdir(backup_dir), reverse=True):
            fp = os.path.join(backup_dir, f)
            if os.path.isfile(fp):
                backups.append({
                    'filename': f,
                    'size_bytes': os.path.getsize(fp),
                    'created': datetime.fromtimestamp(os.path.getmtime(fp)).isoformat(),
                })
        return backups

