import os
import shutil
from datetime import datetime, timezone, timedelta
from flask import current_app
from app.services.audit_service import log_action


def create_backup(db_path: str, backup_dir: str) -> str:
    """Copy the SQLite database file to backup_dir with a timestamp name."""
    os.makedirs(backup_dir, exist_ok=True)
    timestamp = datetime.now(timezone.utc).strftime('%Y%m%dT%H%M%SZ')
    db_name = os.path.basename(db_path)
    backup_filename = f"{db_name}.{timestamp}.bak"
    backup_path = os.path.join(backup_dir, backup_filename)
    shutil.copy2(db_path, backup_path)
    log_action(
        action='backup.create',
        resource_type='backup',
        new_value={'backup_path': backup_path},
    )
    return backup_path


def prune_old_backups(backup_dir: str, retention_days: int | None = None) -> int:
    """Delete backup files older than retention_days. Returns count deleted."""
    if retention_days is None:
        retention_days = current_app.config.get('BACKUP_RETENTION_DAYS', 30)
    cutoff = datetime.now(timezone.utc) - timedelta(days=retention_days)
    deleted = 0
    if not os.path.isdir(backup_dir):
        return deleted
    for fname in os.listdir(backup_dir):
        fpath = os.path.join(backup_dir, fname)
        if not os.path.isfile(fpath):
            continue
        mtime = datetime.fromtimestamp(os.path.getmtime(fpath), tz=timezone.utc)
        if mtime < cutoff:
            os.remove(fpath)
            deleted += 1
    return deleted


def list_backups(backup_dir: str) -> list[dict]:
    if not os.path.isdir(backup_dir):
        return []
    result = []
    for fname in sorted(os.listdir(backup_dir)):
        fpath = os.path.join(backup_dir, fname)
        if os.path.isfile(fpath):
            stat = os.stat(fpath)
            result.append({
                'filename': fname,
                'path': fpath,
                'size_bytes': stat.st_size,
                'created_at': datetime.fromtimestamp(stat.st_mtime, tz=timezone.utc).isoformat(),
            })
    return result
