    border-top: 1px solid var(--gray-100);
}

.checkbox-group {
    display: flex;
    flex-wrap: wrap;
    gap: 0.5rem;
    margin-top: 0.25rem;
}

.star-input {
    display: flex;
    gap: 0.75rem;
    flex-wrap: wrap;
}

/* ------------------------------------------------------------
   10. Tables
   ------------------------------------------------------------ */
.table {
    width: 100%;
    border-collapse: collapse;
    font-size: 0.9rem;
}

.table th {
    text-align: left;
    padding: 0.75rem;
    border-bottom: 2px solid var(--gray-200);
    font-size: 0.8125rem;
    font-weight: 600;
    color: var(--gray-500);
    text-transform: uppercase;
    letter-spacing: 0.03em;
    white-space: nowrap;
}

.table td {
    padding: 0.75rem;
    border-bottom: 1px solid var(--gray-100);
    vertical-align: middle;
}

.table-striped tbody tr:nth-child(even) td {
    background-color: var(--gray-50);
}

.table tbody tr:hover td {
    background-color: var(--gray-50);
}

/* ------------------------------------------------------------
   11. Auth Pages
   ------------------------------------------------------------ */
.auth-container {
    display: flex;
    justify-content: center;
    align-items: center;
    min-height: 80vh;
    padding: 2rem 1rem;
}

.auth-card {
    width: 100%;
    max-width: 400px;
    background: #fff;
    border-radius: var(--radius);
    box-shadow: var(--shadow-lg);
    padding: 2rem;
}

.auth-card h1,
.auth-card h2 {
    text-align: center;
    margin-bottom: 1.5rem;
}

.auth-link {
    text-align: center;
    margin-top: 1rem;
    font-size: 0.875rem;
    color: var(--gray-500);
}

/* ------------------------------------------------------------
   12. Page Header
   ------------------------------------------------------------ */
.page-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 1.5rem;
    flex-wrap: wrap;
    gap: 0.75rem;
}

.page-header h1 {
    margin-bottom: 0;
}

.header-actions {
    display: flex;
    gap: 0.5rem;
    flex-wrap: wrap;
}

.breadcrumb {
    display: inline-block;
    font-size: 0.875rem;
    color: var(--gray-500);
    margin-bottom: 0.5rem;
    text-decoration: none;
}
.breadcrumb:hover {
    color: var(--primary);
}

/* ------------------------------------------------------------
   13. Filter Bar
   ------------------------------------------------------------ */
.filter-bar {
    display: flex;
    gap: 1rem;
    margin-bottom: 1.5rem;
    flex-wrap: wrap;
    align-items: flex-end;
}

.filter-bar .form-input,
.filter-bar .form-select,
.filter-bar select {
    flex: 1;
    min-width: 140px;
    max-width: 280px;
}

/* ------------------------------------------------------------
   14. Pills
   ------------------------------------------------------------ */
.pills {
    display: flex;
    flex-wrap: wrap;
    gap: 0.25rem;
    margin: 0.25rem 0;
}

.pill {
    display: inline-block;
    padding: 0.25rem 0.75rem;
    background: var(--gray-100);
    border-radius: 999px;
    font-size: 0.75rem;
    color: var(--gray-700);
    margin: 0.125rem;
}

/* ------------------------------------------------------------
   15. Alerts
   ------------------------------------------------------------ */
.alert {
    padding: 0.875rem 1rem;
    border-radius: var(--radius);
    margin-bottom: 1rem;
    border-left: 4px solid transparent;
    font-size: 0.9rem;
}

.alert-success {
    background: #f0fdf4;
    border-color: var(--success);
    color: #14532d;
}

.alert-error {
    background: #fff1f2;
    border-color: var(--danger);
    color: #7f1d1d;
}

.alert-warning {
    background: #fffbeb;
    border-color: var(--warning);
    color: #78350f;
}

.alert-info {
    background: #eff6ff;
    border-color: var(--primary);
    color: #1e3a8a;
}

/* ------------------------------------------------------------
   16. Toasts
   ------------------------------------------------------------ */
@keyframes slideIn {
    from { transform: translateX(110%); opacity: 0; }
    to   { transform: translateX(0);    opacity: 1; }
}

#toast-container {
    position: fixed;
    top: 1rem;
    right: 1rem;
    z-index: 9999;
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    pointer-events: none;
}

.toast {
    padding: 0.75rem 1rem;
    border-radius: var(--radius);
    color: #fff;
    font-size: 0.875rem;
    box-shadow: var(--shadow-lg);
    animation: slideIn 0.3s ease-out;
    min-width: 220px;
    max-width: 360px;
    pointer-events: auto;
}

.toast-success  { background: var(--success); }
.toast-error    { background: var(--danger);  }
.toast-warning  { background: var(--warning); }
.toast-info     { background: var(--primary); }

.toast-fade {
    opacity: 0;
    transition: opacity 0.3s;
}

/* ------------------------------------------------------------
   17. Modals
   ------------------------------------------------------------ */
.modal-overlay {
    position: fixed;
    inset: 0;
    background: rgba(0, 0, 0, 0.5);
    z-index: 1000;
    display: flex;
    justify-content: center;
    align-items: center;
}

.modal {
    background: #fff;
    border-radius: var(--radius);
    max-width: 600px;
    width: 90%;
    max-height: 80vh;
    overflow-y: auto;
    position: relative;
    box-shadow: var(--shadow-lg);
    display: flex;
    flex-direction: column;
}

.modal-content {
    background: #fff;
    border-radius: var(--radius);
    padding: 2rem;
    max-width: 600px;
    width: 90%;
    max-height: 80vh;
    overflow-y: auto;
    position: relative;
    box-shadow: var(--shadow-lg);
}

.modal-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 1.25rem 1.5rem;
    border-bottom: 1px solid var(--gray-200);
}

.modal-header h2 {
    margin-bottom: 0;
    font-size: 1.25rem;
}

.modal-body {
    padding: 1.5rem;
    overflow-y: auto;
    flex: 1;
}

.modal-footer {
    padding: 1rem 1.5rem;
    border-top: 1px solid var(--gray-100);
    display: flex;
    justify-content: flex-end;
    gap: 0.5rem;
}

.modal-close {
    position: absolute;
    top: 0.5rem;
    right: 0.5rem;
    background: none;
    border: none;
    font-size: 1.5rem;
    cursor: pointer;
    color: var(--gray-500);
    line-height: 1;
    padding: 0.25rem;
    border-radius: var(--radius);
}
.modal-close:hover {
    color: var(--gray-900);
    background: var(--gray-100);
}

/* ------------------------------------------------------------
   18. Timeline
   ------------------------------------------------------------ */
.timeline {
    border-left: 2px solid var(--gray-200);
    padding-left: 1rem;
    margin-left: 0.5rem;
}

.timeline-item {
    margin-bottom: 1rem;
    position: relative;
}

.timeline-item::before {
    content: '';
    width: 10px;
    height: 10px;
    background: var(--primary);
    border-radius: 50%;
    position: absolute;
    left: -1.35rem;
    top: 0.3rem;
}

/* ------------------------------------------------------------
   19. Star Rating
   ------------------------------------------------------------ */
.star-rating {
    color: #fbbf24;
    font-size: 1.25rem;
    letter-spacing: 2px;
    line-height: 1;
}

.review-stats {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    margin-bottom: 1rem;
    padding: 0.75rem;
    background: var(--gray-50);
    border-radius: var(--radius);
}

.stat-big {
    font-size: 2rem;
    font-weight: 700;
    color: var(--primary);
    line-height: 1;
}

/* ------------------------------------------------------------
   20. Review Cards
   ------------------------------------------------------------ */
.review-card {
    border-left: 3px solid var(--gray-200);
    padding-left: 1rem;
    margin-bottom: 1rem;
}

.review-header {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    flex-wrap: wrap;
    margin-bottom: 0.5rem;
}

.review-excerpt {
    font-style: italic;
    color: var(--gray-700);
    border-left: 3px solid var(--gray-200);
    padding-left: 0.75rem;
    margin: 0.5rem 0;
}

.coach-reply {
    margin-left: 2rem;
    border-left: 3px solid var(--primary);
    padding: 0.75rem 1rem;
    margin-top: 0.5rem;
    background: var(--gray-50);
    border-radius: var(--radius);
}

/* ------------------------------------------------------------
   21. Offline Banner
   ------------------------------------------------------------ */
.offline-banner {
    background: var(--warning);
    color: #fff;
    text-align: center;
    padding: 0.5rem;
    font-size: 0.875rem;
    font-weight: 500;
    position: sticky;
    top: 0;
    z-index: 200;
}

/* ------------------------------------------------------------
   22. Footer
   ------------------------------------------------------------ */
.footer {
    text-align: center;
    padding: 2rem;
    color: var(--gray-500);
    font-size: 0.875rem;
    margin-top: 2rem;
    border-top: 1px solid var(--gray-100);
}

/* ------------------------------------------------------------
   23. Checkbox Grid
   ------------------------------------------------------------ */
.checkbox-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(180px, 1fr));
    gap: 0.5rem;
    margin-top: 0.25rem;
}

.checkbox-label {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    font-size: 0.875rem;
    cursor: pointer;
}

.checkbox-label input[type="checkbox"] {
    width: auto;
    margin: 0;
    flex-shrink: 0;
}

/* ------------------------------------------------------------
   24. Pagination
   ------------------------------------------------------------ */
.pagination {
    display: flex;
    gap: 0.25rem;
    justify-content: center;
    align-items: center;
    margin-top: 1.5rem;
    flex-wrap: wrap;
}

.pagination .btn {
    min-width: 2rem;
}

/* ------------------------------------------------------------
   25. Text Utilities
   ------------------------------------------------------------ */
.text-muted   { color: var(--gray-500); }
.text-center  { text-align: center; }
.text-right   { text-align: right; }
.text-sm      { font-size: 0.875rem; }
.text-xs      { font-size: 0.75rem; }
.muted        { color: var(--gray-500); font-size: 0.8125rem; }
.fw-bold      { font-weight: 700; }
.d-flex       { display: flex; }
.gap-1        { gap: 0.25rem; }
.gap-2        { gap: 0.5rem; }
.mt-1         { margin-top: 0.25rem; }
.mt-2         { margin-top: 0.5rem; }
.mb-1         { margin-bottom: 0.25rem; }
.mb-2         { margin-bottom: 0.5rem; }

/* ------------------------------------------------------------
   26. Listing-Specific
   ------------------------------------------------------------ */
.listing-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
    gap: 1.25rem;
}

.listing-card .card-body {
    padding-top: 0.5rem;
}

.listing-card-header {
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
    gap: 0.5rem;
    margin-bottom: 0.5rem;
}

.listing-card-header h3 {
    margin-bottom: 0;
    font-size: 1rem;
}

.listing-card-footer {
    display: flex;
    gap: 0.5rem;
    margin-top: 0.75rem;
    padding-top: 0.75rem;
    border-top: 1px solid var(--gray-100);
}

.listing-address {
    font-size: 0.875rem;
    color: var(--gray-700);
    margin-bottom: 0.25rem;
}

.listing-rent,
.listing-price {
    font-size: 1.25rem;
    font-weight: 700;
    color: var(--primary);
    margin-bottom: 0.25rem;
}

.listing-dates,
.listing-sqft {
    font-size: 0.8125rem;
    color: var(--gray-500);
}

.listing-meta {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-top: 0.5rem;
}

.status-card {
    background: #fff;
    border-radius: var(--radius);
    box-shadow: var(--shadow);
    padding: 1.25rem;
}

.status-meta {
    font-size: 0.8125rem;
    color: var(--gray-500);
    margin-top: 0.5rem;
    margin-bottom: 0;
}

.status-history {
    margin-top: 1rem;
    border-top: 1px solid var(--gray-100);
    padding-top: 0.75rem;
}

.status-history h4 {
    font-size: 0.875rem;
    font-weight: 600;
    color: var(--gray-500);
    text-transform: uppercase;
    letter-spacing: 0.03em;
    margin-bottom: 0.5rem;
}

.status-history ul {
    list-style: none;
    padding: 0;
    margin: 0;
}

.status-history li {
    display: flex;
    flex-wrap: wrap;
    gap: 0.5rem;
    align-items: center;
    padding: 0.35rem 0;
    border-bottom: 1px solid var(--gray-50);
    font-size: 0.8125rem;
}

.status-actions {
    margin-top: 1rem;
}

.status-actions .form-select,
.status-actions textarea {
    margin-bottom: 0.5rem;
}

/* ------------------------------------------------------------
   27. Drug-Specific
   ------------------------------------------------------------ */
.drug-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
    gap: 1.25rem;
}

.drug-card .card-header {
    flex-wrap: wrap;
    gap: 0.25rem;
}

.drug-strength {
    font-size: 1rem;
    font-weight: 600;
    color: var(--gray-900);
    margin-bottom: 0.25rem;
}

.search-snippet {
    font-size: 0.875rem;
    color: var(--gray-700);
    margin-top: 0.25rem;
}

.search-snippet mark {
    background: #fef08a;
    color: inherit;
    border-radius: 2px;
    padding: 0 1px;
}

/* ------------------------------------------------------------
   28. Search Input
   ------------------------------------------------------------ */
.search-input {
    max-width: 400px;
}

/* ------------------------------------------------------------
   29. Detail List (dl)
   ------------------------------------------------------------ */
.detail-list {
    display: grid;
    grid-template-columns: max-content 1fr;
    gap: 0.375rem 1rem;
    font-size: 0.9rem;
    margin-bottom: 0.5rem;
}

.detail-list dt {
    font-weight: 600;
    color: var(--gray-500);
    text-transform: uppercase;
    font-size: 0.75rem;
    letter-spacing: 0.04em;
    align-self: center;
}

.detail-list dd {
    margin: 0;
    align-self: center;
}

/* ------------------------------------------------------------
   30. Empty State
   ------------------------------------------------------------ */
.empty-state {
    text-align: center;
    padding: 3rem 1rem;
    color: var(--gray-500);
}

.empty-state p {
    margin-bottom: 1rem;
    font-size: 1.0625rem;
}

/* ------------------------------------------------------------
   31. HTMX
   ------------------------------------------------------------ */
.htmx-indicator {
    display: none;
}

.htmx-request .htmx-indicator {
    display: inline-block;
}

.htmx-settling {
    opacity: 0.8;
}

.htmx-swapping {
    opacity: 0;
}

/* ------------------------------------------------------------
   32. Preview Modal (Listing)
   ------------------------------------------------------------ */
.preview-badge-row {
    margin-bottom: 1rem;
}

.preview-section {
    margin-bottom: 1rem;
    padding-bottom: 1rem;
    border-bottom: 1px solid var(--gray-100);
}

.preview-section:last-child {
    border-bottom: none;
}

.preview-section h3 {
    font-size: 0.875rem;
    font-weight: 600;
    text-transform: uppercase;
    color: var(--gray-500);
    letter-spacing: 0.04em;
    margin-bottom: 0.4rem;
}

.amenity-list {
    list-style: none;
    padding: 0;
    margin: 0;
    display: flex;
    flex-wrap: wrap;
    gap: 0.375rem;
}

.amenity-list li {
    background: var(--gray-100);
    border-radius: 999px;
    padding: 0.2rem 0.65rem;
    font-size: 0.8125rem;
    color: var(--gray-700);
}

/* ------------------------------------------------------------
   33. Moderation
   ------------------------------------------------------------ */
.report-card {
    border-left: 3px solid var(--warning);
}

/* ------------------------------------------------------------
   Responsive Breakpoints
   ------------------------------------------------------------ */
@media (max-width: 768px) {
    .navbar {
        flex-direction: column;
        align-items: flex-start;
        gap: 0.5rem;
        padding: 0.75rem 1rem;
    }

    .nav-links {
        display: flex;
        flex-wrap: wrap;
        gap: 0.25rem;
    }

    .nav-links a {
        margin-left: 0;
        margin-right: 0.75rem;
    }

    .grid,
    .listing-grid,
    .drug-grid {
        grid-template-columns: 1fr;
    }

    .detail-layout {
        grid-template-columns: 1fr;
    }

    .filter-bar {
        flex-direction: column;
        align-items: stretch;
    }

    .filter-bar .form-input,
    .filter-bar .form-select,
    .filter-bar select {
        max-width: 100%;
    }

    .modal-content,
    .modal {
        width: 95%;
        padding: 1.25rem;
    }

    .table-wrapper {
        overflow-x: auto;
    }

    .table {
        min-width: 560px;
    }

    .form-row {
        grid-template-columns: 1fr;
    }

    .page-header {
        flex-direction: column;
        align-items: flex-start;
    }

    .form-actions {
        flex-direction: column-reverse;
    }

    .form-actions .btn {
        width: 100%;
        text-align: center;
    }
}

@media (max-width: 480px) {
    .container,
    .main-content {
        padding: 0 0.5rem;
    }

    h1 { font-size: 1.5rem; }
    h2 { font-size: 1.25rem; }
    h3 { font-size: 1.1rem; }

    .auth-card {
        padding: 1.25rem;
    }

    .card {
        padding: 1rem;
    }

    .form-card {
        padding: 1rem;
    }

    .checkbox-grid {
        grid-template-columns: 1fr;
    }

    .search-input {
        max-width: 100%;
    }

    #toast-container {
        left: 0.5rem;
        right: 0.5rem;
    }

    .toast {
        max-width: 100%;
        min-width: 0;
    }
}
"}

